  ovSeeTokens: { en: 'See the tokens', es: 'Ver los tokens', fr: 'Voir les tokens', de: 'Tokens ansehen', ja: 'トークンを見る', pt: 'Ver os tokens', zh: '查看令牌', ar: 'عرض الرموز' },
  haptics: { en: 'Haptics', es: 'Vibración', fr: 'Retour haptique', de: 'Haptik', ja: '触覚フィードバック', pt: 'Resposta tátil', zh: '触感反馈', ar: 'اهتزاز اللمس' },
  hapticsHelp: { en: 'Vibration feedback on tap. Works on supported touch devices; a no-op on desktop.', es: 'Vibración al tocar. Funciona en dispositivos táctiles compatibles; sin efecto en escritorio.', fr: 'Vibration au toucher. Fonctionne sur les appareils tactiles compatibles ; sans effet sur ordinateur.', de: 'Vibration beim Tippen. Funktioniert auf unterstützten Touch-Geräten; ohne Wirkung am Desktop.', ja: 'タップ時の振動フィードバック。対応するタッチデバイスで動作し、デスクトップでは何もしません。', pt: 'Vibração ao tocar. Funciona em dispositivos táteis compatíveis; sem efeito no computador.', zh: '点按时的振动反馈。在受支持的触摸设备上有效；在桌面端无效。', ar: 'اهتزاز عند اللمس. يعمل على أجهزة اللمس المدعومة؛ بلا تأثير على سطح المكتب.' },
  visualFeedback: { en: 'Visual feedback', es: 'Retroalimentación visual', fr: 'Retours visuels', de: 'Visuelles Feedback', ja: 'ビジュアルフィードバック', pt: 'Retroalimentação visual', zh: '视觉反馈', ar: 'ردود فعل بصرية' },
  visualFeedbackHelp: { en: 'A subtle on-screen effect on tap, in lockstep with haptics. Works for the mouse too, so it is the desktop stand-in for a taptic.', es: 'Un efecto sutil en pantalla al tocar, sincronizado con los hápticos. También funciona con el ratón, por lo que es el sustituto de escritorio para un táptico.', fr: 'Un effet subtil à l\'écran au toucher, synchronisé avec les retours haptiques. Fonctionne aussi à la souris, c\'est donc le remplaçant de bureau pour un taptic.', de: 'Ein subtiler Bildschirmeffekt beim Tippen, synchronisiert mit Haptics. Funktioniert auch mit der Maus, daher ist es der Desktop-Ersatz für ein Taptic.', ja: 'タップ時の微妙なオンスクリーン効果で、ハプティクスと同期します。マウスでも機能するため、デスクトップのタップティック代替となります。', pt: 'Um efeito sutil na tela ao tocar, em sincronismo com os hápticos. Funciona também com o mouse, portanto é o substituto de desktop para um táptico.', zh: '点击时的细微屏幕效果,与触觉同步。也适用于鼠标,因此它是桌面版触觉反馈的替代品。', ar: 'تأثير خفي على الشاشة عند النقر, متزامن مع التحكم اللمسي. يعمل مع الماوس أيضاً, لذا فهو بديل سطح المكتب للتأثير اللمسي.' },
  direction: { en: 'Direction', es: 'Dirección', fr: 'Sens de lecture', de: 'Schreibrichtung', ja: '文字方向', pt: 'Direção', zh: '文字方向', ar: 'الاتجاه' },
  ltr: { en: 'Left to right', es: 'De izquierda a derecha', fr: 'De gauche à droite', de: 'Links nach rechts', ja: '左から右', pt: 'Da esquerda para a direita', zh: '从左到右', ar: 'من اليسار إلى اليمين' },
  rtl: { en: 'Right to left', es: 'De derecha a izquierda', fr: 'De droite à gauche', de: 'Rechts nach links', ja: '右から左', pt: 'Da direita para a esquerda', zh: '从右到左', ar: 'من اليمين إلى اليسار' },
  ovBlueprints: { en: 'Blueprints', es: 'Planos', fr: 'Plans', de: 'Baupläne', ja: '設計図', pt: 'Plantas', zh: '蓝图', ar: 'المخططات' },
  ovBlueprintsBody: {
    en: 'Every atom, measured. Scroll the gallery and open any component to see its anatomy, sizing, and specs.',
    es: 'Cada átomo, medido. Recorre la galería y abre cualquier componente para ver su anatomía, tamaños y especificaciones.',
    fr: 'Chaque atome, mesuré. Parcourez la galerie et ouvrez un composant pour découvrir son anatomie, ses tailles et ses specs.',
    de: 'Jedes Atom, vermessen. Scrolle durch die Galerie und öffne eine Komponente, um Anatomie, Größen und Specs zu sehen.',
    ja: 'すべてのアトムを計測。ギャラリーをスクロールして任意のコンポーネントを開くと、構造・サイズ・仕様を確認できます。',
  pt: 'Cada átomo, medido. Role pela galeria e abra qualquer componente para ver sua anatomia, dimensionamento e especificações.', zh: '每个原子,已测量。滚动库并打开任何组件以查看其解剖结构、大小和规格。', ar: 'كل ذرة, مقاسة. قم بالتمرير عبر المعرض وفتح أي مكون لرؤية تشريحه وحجمه والمواصفات.' },

