  trNoStrictChecks: { en: 'no strict checks', es: 'sin comprobaciones estrictas', fr: 'pas de contrôles stricts', de: 'keine strikten Prüfungen', ja: '厳密なチェックなし', pt: 'sem verificações rigorosas', zh: '无严格检查', ar: 'لا توجد فحوصات صارمة' },
