  wizHintName: { en: 'Shown on everything you publish.', es: 'Se muestra en todo lo que publiques.', fr: 'Affiché sur tout ce que vous publiez.', de: 'Wird auf allem angezeigt, das Sie veröffentlichen.', ja: '公開するすべてのものに表示されます。', pt: 'Mostrado em tudo que você publica.', zh: '显示在您发布的所有内容上。', ar: 'معروض على كل ما تنشره.' },
  wizValidateName: { en: 'Add a display name before moving on.', es: 'Añade un nombre de visualización antes de continuar.', fr: 'Ajoutez un nom d\'affichage avant de continuer.', de: 'Fügen Sie einen Anzeigenamen hinzu, bevor Sie fortfahren.', ja: '続行する前に表示名を追加してください。', pt: 'Adicione um nome de exibição antes de prosseguir.', zh: '继续之前请添加显示名称。', ar: 'أضف اسم عرض قبل المتابعة.' },
  wizFieldHandle: { en: 'Handle', es: 'Identificador', fr: 'Identifiant', de: 'Griff', ja: 'ハンドル', pt: 'Identificador', zh: '句柄', ar: 'المقبض' },
  wizHintHandle: { en: 'Checked against the server when you press Next.', es: 'Se verifica con el servidor cuando presionas Siguiente.', fr: 'Vérifié auprès du serveur lorsque vous appuyez sur Suivant.', de: 'Wird mit dem Server überprüft, wenn Sie Next drücken.', ja: 'Nextを押すとサーバーで確認されます。', pt: 'Verificado com o servidor quando você pressiona Próximo.', zh: '当您按下下一步时，将根据服务器进行检查。', ar: 'يتم التحقق منه مع الخادم عند الضغط على التالي.' },
