  wizReviewFinish: { en: 'Press Done to finish.', es: 'Presiona Listo para terminar.', fr: 'Appuyez sur Terminé pour terminer.', de: 'Drücken Sie Fertig, um zu beenden.', ja: '完了を押して終了します。', pt: 'Pressione Concluído para terminar.', zh: '按完成以结束。', ar: 'اضغط على تم للانتهاء.' },
  wizAsyncConfirm: { en: 'The handle is yours. Press Done to keep it.', es: 'El identificador es tuyo. Presiona Listo para mantenerlo.', fr: 'Le identifiant est le vôtre. Appuyez sur Terminé pour le garder.', de: 'Das Griff ist dein. Drücken Sie Fertig, um es zu behalten.', ja: 'ハンドルはあなたのものです。完了を押して保持してください。', pt: 'O identificador é seu. Pressione Concluído para mantê-lo.', zh: '句柄是你的。按完成以保留它。', ar: 'المقبض لك. اضغط على تم للاحتفاظ به.' },
  wizPlanScope: { en: 'Pick what the project covers.', es: 'Elige qué cubre el proyecto.', fr: 'Choisissez ce que le projet couvre.', de: 'Wählen Sie, was das Projekt abdeckt.', ja: 'プロジェクトが何をカバーするか選択してください。', pt: 'Escolha o que o projeto cobre.', zh: '选择项目涵盖的内容。', ar: 'اختر ما يغطيه المشروع.' },
  wizPlanTeam: { en: 'Invite the people who will work on it.', es: 'Invita a la gente que trabajará en él.', fr: 'Invitez les gens qui travailleront dessus.', de: 'Laden Sie die Personen ein, die daran arbeiten werden.', ja: 'それに取り組む人々を招待してください。', pt: 'Convide as pessoas que trabalharão nele.', zh: '邀请将在其上工作的人员。', ar: 'ادع الأشخاص الذين سيعملون عليه.' },
  wizPlanBilling: { en: 'Choose a plan and confirm.', es: 'Elige un plan y confirma.', fr: 'Choisissez un plan et confirmez.', de: 'Wählen Sie einen Plan und bestätigen Sie.', ja: 'プランを選択して確認してください。', pt: 'Escolha um plano e confirme.', zh: '选择计划并确认。', ar: 'اختر خطة وأكد.' },
  wizCompletedLabel: { en: 'Completed:', es: 'Completado:', fr: 'Terminé :', de: 'Abgeschlossen:', ja: '完了:', pt: 'Concluído:', zh: '已完成:', ar: 'مكتمل:' },
