  visualfeedbackEffectVariant: { en: 'Effect variant', es: 'Variante de efecto', fr: 'Variante d\'effet', de: 'Effekt-Variante', ja: 'エフェクトバリアント', pt: 'Variante de efeito', zh: '效果变体', ar: 'متغير التأثير' },
